export function renderGallery(widgetMap, report) {
  const lines = [
    "# Legacy Card Gallery",
    "",
    "This file is generated by `tools/legacy-migrator/scan-legacy-inventory.mjs`.",
    "",
    "| Legacy widget | Title | Group | Status | Target | Variant | Notes |",
    "| --- | --- | --- | --- | --- | --- | --- |",
  ];
  for (const item of sortedWidgets(widgetMap)) {
    lines.push(
      `| \`${item.legacy_id}\` | ${escapeTable(item.title)} | ${item.group} | ${item.status} | \`${item.target}\` | ${item.variant || ""} | ${escapeTable(item.notes)} |`,
    );
  }
  lines.push("", "## Coverage", "");
  lines.push(`- Total widgets: ${report.summary.widgets.total}`);
  lines.push(`- Native wrappers: ${report.summary.widgets.native}`);
  lines.push(`- Non-native widgets: ${report.summary.widgets.non_native}`);
  lines.push(`- Manual review count: ${report.summary.widgets.status_counts.legacy_only || 0}`);
  return lines.join("\n");
}

export function renderLayoutMap(widgetMap, report) {
  const lines = [
    "# Legacy Layout Map",
    "",
    "This file is generated by `tools/legacy-migrator/scan-legacy-inventory.mjs`.",
    "",
    "## Layout Rules",
    "",
    "- Legacy Grid uses `gridX`, `gridY`, `gridW`, `gridH`, 12 columns, collision handling, sparse movement, and compaction.",
    "- Legacy Free uses percentage `x`, `y`, `w`, `h`, and `z`, with overlap and absolute placement.",
    "- New default migration maps Grid to HA Sections and `grid_options`.",
    "- New advanced migration maps Free to Yeelight Canvas View `view_layout`.",
    "",
    "## Widget Size Mapping",
    "",
    "| Legacy widget | Size | Layout | Status | Target layout |",
    "| --- | --- | --- | --- | --- |",
  ];
  for (const item of sortedWidgets(widgetMap)) {
    lines.push(
      `| \`${item.legacy_id}\` | ${item.legacy_size} | ${item.legacy_layout} | ${item.status} | ${layoutTarget(item)} |`,
    );
  }
  lines.push("", "## Lovelace Views", "");
  lines.push("| Path | Title | Migration |");
  lines.push("| --- | --- | --- |");
  for (const view of report.lovelace.views) {
    lines.push(`| \`${view.path}\` | ${escapeTable(view.title)} | ${view.migration} |`);
  }
  return lines.join("\n");
}

export function renderAssetsMap(assetInventory) {
  const lines = [
    "# Legacy Assets Map",
    "",
    "This file is generated by `tools/legacy-migrator/scan-legacy-inventory.mjs`.",
    "",
    `Total assets: ${assetInventory.total}`,
    "",
    "## Counts By Kind",
    "",
    "| Kind | Count |",
    "| --- | ---: |",
  ];
  for (const [kind, count] of Object.entries(assetInventory.byKind).sort()) {
    lines.push(`| ${kind} | ${count} |`);
  }
  lines.push("", "## Asset Entries", "");
  lines.push("| File | Kind | Migration |");
  lines.push("| --- | --- | --- |");
  for (const asset of assetInventory.entries) {
    lines.push(`| \`${asset.file}\` | ${asset.kind} | ${asset.migration} |`);
  }
  return lines.join("\n");
}

export function renderMigrationReport(report) {
  const lines = [
    "# Legacy Migration Report",
    "",
    "This file is generated by `tools/legacy-migrator/scan-legacy-inventory.mjs`.",
    "",
    "## Summary",
    "",
    `- Widgets: ${report.summary.widgets.total}`,
    `- Native wrappers: ${report.summary.widgets.native}`,
    `- Non-native widgets: ${report.summary.widgets.non_native}`,
    `- Lovelace resources: ${report.summary.lovelace.resources}`,
    `- Lovelace views: ${report.summary.lovelace.views}`,
    `- External community resources currently referenced: ${report.summary.lovelace.external_community_resources}`,
    `- Assets: ${report.summary.assets.total}`,
    `- Legacy files scanned: ${report.summary.files.total}`,
    "",
    "## Widget Status Counts",
    "",
    "| Status | Count |",
    "| --- | ---: |",
  ];
  for (const [status, count] of Object.entries(report.summary.widgets.status_counts).sort()) {
    lines.push(`| ${status} | ${count} |`);
  }
  lines.push("", "## Lovelace Resources", "");
  lines.push("| URL | Type | Migration |");
  lines.push("| --- | --- | --- |");
  for (const resource of report.lovelace.resources) {
    lines.push(`| \`${resource.url}\` | ${resource.type} | ${resource.migration} |`);
  }
  lines.push("", "## Backend Contracts", "");
  lines.push("| File | Migration | Contracts |");
  lines.push("| --- | --- | --- |");
  for (const entry of report.backend) {
    lines.push(
      `| \`${entry.file}\` | ${entry.migration} | ${entry.contracts.join(", ") || "review"} |`,
    );
  }
  lines.push("", "## Package Inputs", "");
  lines.push("| File | Migration | Domains |");
  lines.push("| --- | --- | --- |");
  for (const pkg of report.package_inventory) {
    lines.push(
      `| \`${pkg.file}\` | ${pkg.migration} | ${Object.keys(pkg.domains).join(", ") || "none"} |`,
    );
  }
  return lines.join("\n");
}

function sortedWidgets(widgetMap) {
  return Object.values(widgetMap).sort(
    (a, b) => a.legacy_order - b.legacy_order || a.legacy_id.localeCompare(b.legacy_id),
  );
}

function layoutTarget(item) {
  if (item.status === "native_recipe") return "HA Sections / native card recipe";
  if (item.target.includes("floorplan") || item.target.includes("image")) {
    return "Sections by default; Canvas/Floorplan optional";
  }
  if (item.group === "core" || item.group === "device" || item.group === "routine") {
    return "HA Sections";
  }
  if (item.group === "system") return "Advanced profile Sections";
  return "HA Sections / optional Canvas";
}

function escapeTable(value) {
  return String(value || "").replace(/\|/g, "\\|").replace(/\n/g, " ");
}
